// ===============================
// src/services/api.js
// ===============================
const API_BASE = "http://localhost:8000";

export const checkHealth = async () => {
  const res = await fetch(`${API_BASE}/health`);
  return res.json();
};

export const processCheque = async (file) => {
  const formData = new FormData();
  formData.append("file", file);

  const res = await fetch(`${API_BASE}/api/v1/cheque/process`, {
    method: "POST",
    body: formData,
  });

  return res.json();
};
